func BenchmarkResponseCacheRetainedHeap(b *testing.B) {
	const rateLimitsPerProject = 3000
	b.ReportAllocs()

	for range b.N {
		cache := &responseCache{}
		runtime.GC()
		var before runtime.MemStats
		runtime.ReadMemStats(&before)

		for project := 0; project < defaultResponseCacheMaxEntries+1; project++ {
			limits := make([]any, rateLimitsPerProject)
			for limit := range rateLimitsPerProject {
				limits[limit] = map[string]any{
					"object":                           "project.rate_limit",
					"id":                               fmt.Sprintf("rl-%d-%d", project, limit),
					"model":                            fmt.Sprintf("model-%d-%d", project, limit),
					"max_requests_per_1_minute":        float64(limit + 1),
					"max_tokens_per_1_minute":          float64((limit + 1) * 1000),
					"max_images_per_1_minute":          nil,
					"max_audio_megabytes_per_1_minute": nil,
					"max_requests_per_1_day":           nil,
					"batch_1_day_max_input_tokens":     float64((limit + 1) * 10000),
				}
			}
			key := responseCacheKey{
				name:   "project_rate_limits",
				values: fmt.Sprintf("proj-%d", project),
			}
			payload, err := json.Marshal(map[string]any{
				"object":   "list",
				"data":     limits,
				"has_more": false,
				"next":     nil,
			})
			if err != nil {
				b.Fatalf("marshal representative response: %v", err)
			}
			var response map[string]any
			if err := json.Unmarshal(payload, &response); err != nil {
				b.Fatalf("unmarshal representative response: %v", err)
			}
			if _, err := cache.get(context.Background(), key, func(context.Context) (map[string]any, error) {
				return response, nil
			}); err != nil {
				b.Fatalf("cache load returned error: %v", err)
			}
		}

		runtime.GC()
		var after runtime.MemStats
		runtime.ReadMemStats(&after)
		cache.mu.Lock()
		retainedEntries := cache.lru.Len()
		cache.mu.Unlock()
		if retainedEntries != defaultResponseCacheMaxEntries {
			b.Fatalf("expected %d retained entries, got %d", defaultResponseCacheMaxEntries, retainedEntries)
		}

		retainedBytes := int64(after.HeapAlloc) - int64(before.HeapAlloc)
		if retainedBytes < 0 {
			retainedBytes = 0
		}
		b.ReportMetric(float64(retainedBytes)/(1024*1024), "retained-MiB")
		b.ReportMetric(float64(retainedBytes)/float64(retainedEntries), "retained-B/entry")
		b.ReportMetric(float64(retainedEntries), "retained-entries")
		runtime.KeepAlive(cache)
	}
}

func TestAddStringBodyFieldOmitsNullValues(t *testing.T) {
	body := map[string]any{}
	AddStringBodyField(body, "geography", types.StringNull())
	if _, ok := body["geography"]; ok {
		t.Fatalf("expected null create value to be omitted, got %#v", body)
	}

	AddStringBodyField(body, "name", types.StringValue("terraform-managed"))
	if body["name"] != "terraform-managed" {
		t.Fatalf("expected non-null value to be included, got %#v", body)
	}
}

func TestSetBodyFieldCreatesNestedObjects(t *testing.T) {
	body := map[string]any{}
	SetBodyField(body, []string{"notification_channel", "type"}, "email")
	SetBodyField(body, []string{"notification_channel", "recipients"}, []string{"terraform@example.com"})

	channel, ok := body["notification_channel"].(map[string]any)
	if !ok {
		t.Fatalf("expected nested notification channel body, got %#v", body)
	}
	if channel["type"] != "email" {
		t.Fatalf("expected nested type, got %#v", body)
	}
	recipients, ok := channel["recipients"].([]string)
	if !ok || len(recipients) != 1 || recipients[0] != "terraform@example.com" {
		t.Fatalf("expected nested recipients, got %#v", body)
	}
}

func TestAddInt64BodyFieldIncludesIntegerValues(t *testing.T) {
	body := map[string]any{}
	AddInt64BodyField(body, "threshold_amount", types.Int64Value(1000))
	if body["threshold_amount"] != int64(1000) {
		t.Fatalf("expected int64 body value, got %#v", body)
	}
}

func TestAddNullableStringBodyFieldForUpdateSendsNullOnlyForClears(t *testing.T) {
	body := map[string]any{}
	AddNullableStringBodyFieldForUpdate(body, "geography", types.StringNull(), types.StringNull())
	if _, ok := body["geography"]; ok {
		t.Fatalf("expected unchanged null update value to be omitted, got %#v", body)
	}

	AddNullableStringBodyFieldForUpdate(body, "external_key_id", types.StringNull(), types.StringValue("key_123"))
	value, ok := body["external_key_id"]
	if !ok || value != nil {
		t.Fatalf("expected explicit null clear, got %#v", body)
	}

	AddNullableStringBodyFieldForUpdate(body, "description", types.StringValue("updated"), types.StringValue("old"))
	if body["description"] != "updated" {
		t.Fatalf("expected update value to be included, got %#v", body)
	}
}

func TestApplyStringResponseFieldRequiresIdentityValue(t *testing.T) {
	var value types.String
	err := ApplyStringResponseField(map[string]any{}, []string{"id"}, &value, true)
	if err == nil || !strings.Contains(err.Error(), "missing required response field") {
		t.Fatalf("expected missing required response field error, got %v", err)
	}
}

func TestApplyStringResponseFieldRejectsMalformedValue(t *testing.T) {
	var value types.String
	err := ApplyStringResponseField(map[string]any{"id": []any{"not-a-string"}}, []string{"id"}, &value, true)
	if err == nil || !strings.Contains(err.Error(), "not a string-compatible value") {
		t.Fatalf("expected malformed string response field error, got %v", err)
	}
}

func TestApplyInt64ResponseFieldMissingOptionalClearsUnknown(t *testing.T) {
	value := types.Int64Unknown()
	err := ApplyInt64ResponseField(map[string]any{}, []string{"limit"}, &value, false)
	if err != nil {
		t.Fatalf("ApplyInt64ResponseField returned error: %v", err)
	}
	if !value.IsNull() {
		t.Fatalf("expected missing optional unknown value to become null, got %#v", value)
	}
}

func TestResponseObjectListRejectsMalformedItems(t *testing.T) {
	_, err := ResponseObjectList(map[string]any{"data": []any{"not-an-object"}}, "data", true)
	if err == nil || !strings.Contains(err.Error(), "item 0 is not an object") {
		t.Fatalf("expected malformed response object list error, got %v", err)
	}
}

func TestResponseObjectByFieldSelectsMatchingItem(t *testing.T) {
	response := map[string]any{
		"data": []any{
			map[string]any{"id": "alert_1", "threshold_amount": float64(1000)},
			map[string]any{"id": "alert_2", "threshold_amount": float64(2000)},
		},
	}
	item, found, err := ResponseObjectByField(response, "data", "id", "alert_2")
	if err != nil {
		t.Fatalf("ResponseObjectByField returned error: %v", err)
	}
	if !found {
		t.Fatalf("expected item to be found")
	}
	if item["threshold_amount"] != float64(2000) {
		t.Fatalf("unexpected selected item: %#v", item)
	}
}
